using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace YourNamespace.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class UploadController : ControllerBase
    {
        private readonly IWebHostEnvironment _env;

        public UploadController(IWebHostEnvironment env)
        {
            _env = env;
        }

        [HttpPost]
        public IActionResult UploadFile(IFormFile file)
        {
            if (file == null || file.Length == 0)
                return BadRequest("No file provided");

            string allowedExtensions = ".jpg,.jpeg,.png,.gif,.bmp,.pdf,.docx,.xlsx,.pptx";
            var extension = "." + file.FileName.Split('.').Last().ToLower();

            if (!allowedExtensions.Contains(extension))
                return BadRequest($"Invalid file type. Only {allowedExtensions} are supported");

            string filePath = Path.Combine(_env.WebRootPath, "uploads", Guid.NewGuid() + extension);
            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                file.CopyTo(stream);
            }

            return Ok(new { FilePath = filePath });
        }
    }
}